mapper.select:
SELECT c.id, c.notice_id, c.user_id, c.content, c.create_time, c.update_time, c.status, c.parent_id, u.username, u.img as user_avatar, w.title as notice_title FROM comment c LEFT JOIN sysuser u ON c.user_id = u.id LEFT JOIN webnotice w ON c.notice_id = w.id
c.status = '1'
AND c.notice_id = #{noticeId}
AND c.user_id = #{userId}
AND c.content LIKE CONCAT('%',#{content},'%')
ORDER BY c.create_time DESC
